"use strict";(self.webpackChunkailmanac=self.webpackChunkailmanac||[]).push([["9010"],{95391(e,t,n){n.r(t),n.d(t,{metadata:()=>s,default:()=>d,frontMatter:()=>r,contentTitle:()=>i,toc:()=>c,assets:()=>l});var s=JSON.parse('{"id":"models/why-agents-burn-tokens","title":"Why AI Agents Burn Tokens (and How to Cap the Bill)","description":"Agentic runs cost 50\u20131000x a chat \u2014 not because the model is dumber, but because of the context snowball. The mechanism, the surprising numbers, and the four levers that actually cut the bill across Claude, GPT, Gemini, and open models.","source":"@site/docs/models/why-agents-burn-tokens.mdx","sourceDirName":"models","slug":"/models/why-agents-burn-tokens","permalink":"/ailmanac/es/docs/models/why-agents-burn-tokens","draft":false,"unlisted":false,"editUrl":"https://github.com/derob98/ailmanac/tree/main/docs/models/why-agents-burn-tokens.mdx","tags":[],"version":"current","sidebarPosition":10.5,"frontMatter":{"sidebar_position":10.5,"title":"Why AI Agents Burn Tokens (and How to Cap the Bill)","description":"Agentic runs cost 50\u20131000x a chat \u2014 not because the model is dumber, but because of the context snowball. The mechanism, the surprising numbers, and the four levers that actually cut the bill across Claude, GPT, Gemini, and open models.","keywords":["agent token cost","agentic cost control","context snowball","token budget cap","multi-agent cost","orchestrator worker","model tier routing","claude code cost","cursor cost"]},"sidebar":"docs","previous":{"title":"Cu\xe1nto cuesta realmente la IA (entre proveedores)","permalink":"/ailmanac/es/docs/models/what-ai-costs-across-providers"},"next":{"title":"Crear agentes de IA locales","permalink":"/ailmanac/es/docs/models/local-ai-agents"}}'),o=n(74848),a=n(28453);let r={sidebar_position:10.5,title:"Why AI Agents Burn Tokens (and How to Cap the Bill)",description:"Agentic runs cost 50\u20131000x a chat \u2014 not because the model is dumber, but because of the context snowball. The mechanism, the surprising numbers, and the four levers that actually cut the bill across Claude, GPT, Gemini, and open models.",keywords:["agent token cost","agentic cost control","context snowball","token budget cap","multi-agent cost","orchestrator worker","model tier routing","claude code cost","cursor cost"]},i,l={},c=[{value:"The context snowball: why cost grows quadratically",id:"the-context-snowball-why-cost-grows-quadratically",level:2},{value:"The numbers that surprise people",id:"the-numbers-that-surprise-people",level:2},{value:"Your tool surface is part of the bill",id:"your-tool-surface-is-part-of-the-bill",level:2},{value:"The four levers that actually cut the bill",id:"the-four-levers-that-actually-cut-the-bill",level:2},{value:"When an agent is the wrong tool",id:"when-an-agent-is-the-wrong-tool",level:2},{value:"Sources &amp; further reading",id:"sources--further-reading",level:2}];function h(e){let t={a:"a",em:"em",h2:"h2",li:"li",p:"p",strong:"strong",ul:"ul",...(0,a.R)(),...e.components},{Callout:n,Flashcards:s,LevelBadge:r,PromptCard:i,Quiz:l,Steps:c,VerifyNote:h}=t;return n||u("Callout",!0),s||u("Flashcards",!0),r||u("LevelBadge",!0),i||u("PromptCard",!0),l||u("Quiz",!0),c||u("Steps",!0),h||u("VerifyNote",!0),(0,o.jsxs)(o.Fragment,{children:[(0,o.jsx)(r,{level:"intermediate"}),"\n",(0,o.jsxs)(t.p,{children:["A chat turn costs a fraction of a cent. The ",(0,o.jsx)(t.strong,{children:"same question handed to an agent"})," \u2014 one that reads files, calls tools, and loops until done \u2014 can cost dollars. Teams are discovering this the hard way: a coding agent left running racks up a bill that a human at a keyboard never would. The scary part isn't the average; it's that you ",(0,o.jsx)(t.strong,{children:"can't predict it in advance"}),", and the cost of the ",(0,o.jsx)(t.em,{children:"same task"})," can swing wildly."]}),"\n",(0,o.jsxs)(t.p,{children:["This page explains ",(0,o.jsx)(t.strong,{children:"why"})," agents burn tokens (the mechanism is not what most people guess), shows the numbers that surprise even experienced builders, and gives you the four levers that actually cut the bill \u2014 the same levers whether you're on Claude Code, Cursor, Codex, or a home-grown loop over any model."]}),"\n",(0,o.jsx)(n,{type:"objectives",items:["Explain the context snowball \u2014 why agent cost grows roughly QUADRATICALLY with steps, not linearly","Cite the real multipliers: agentic tasks ~1000x a chat's tokens, and the SAME task varying up to 30x","Know when a second agent is worth it \u2014 and the benchmark showing it usually isn't","Pull the four cost levers that work: budget caps, prompt caching, model-tier routing, context pruning","Diagnose a runaway agent bill and put a hard ceiling on it"]}),"\n",(0,o.jsx)(h,{lastVerified:"2026-07-15",source:"https://digitaleconomy.stanford.edu/news/how-are-ai-agents-spending-your-tokens/",children:(0,o.jsxs)(t.p,{children:["Per-token prices, per-developer monthly spend, and which model is cheapest change almost monthly \u2014 treat every dollar figure here as perishable and illustrative. The ",(0,o.jsx)(t.strong,{children:"mechanism"})," (context snowball, re-read tax) and the ",(0,o.jsx)(t.strong,{children:"levers"})," are durable; the exact ratios come from 2026 benchmarks and research linked in Sources. Confirm today's rates on each provider's pricing page before quoting a bill to anyone."]})}),"\n",(0,o.jsx)(t.h2,{id:"the-context-snowball-why-cost-grows-quadratically",children:"The context snowball: why cost grows quadratically"}),"\n",(0,o.jsxs)(t.p,{children:["Here's the trap. A chat is ",(0,o.jsx)(t.strong,{children:"one turn"})," \u2014 one input, one output, done. An agent is a ",(0,o.jsx)(t.strong,{children:"loop"}),": it reads a task, takes an action, reads the result, takes the next action, and so on until the job is finished. The catch is that ",(0,o.jsx)(t.strong,{children:"on every step, the model re-reads the entire accumulated conversation so far"})," \u2014 the original prompt, every prior action, and every tool result \u2014 before deciding what to do next."]}),"\n",(0,o.jsxs)(t.p,{children:["So the input grows on every step, and you ",(0,o.jsx)(t.strong,{children:"pay for the whole snowball again each time it rolls forward"}),":"]}),"\n",(0,o.jsxs)(t.ul,{children:["\n",(0,o.jsx)(t.li,{children:"Step 1 processes the prompt."}),"\n",(0,o.jsxs)(t.li,{children:["Step 2 re-reads the prompt ",(0,o.jsx)(t.strong,{children:"+ step 1's action + result"}),"."]}),"\n",(0,o.jsxs)(t.li,{children:["Step 3 re-reads ",(0,o.jsx)(t.strong,{children:"all of that + step 2's action + result"}),"."]}),"\n",(0,o.jsx)(t.li,{children:"\u2026and so on."}),"\n"]}),"\n",(0,o.jsxs)(t.p,{children:["Add up the input across a run and the total scales ",(0,o.jsx)(t.strong,{children:"roughly with the square of the number of steps"}),", not linearly. The Stanford Digital Economy Lab found agentic tasks to be ",(0,o.jsx)(t.em,{children:'"uniquely expensive, consuming 1000x more tokens than code reasoning and code chat"'})," \u2014 and crucially, it's the ",(0,o.jsx)(t.strong,{children:"input"})," tokens that dominate, not the output. The agent isn't writing more; it's ",(0,o.jsx)(t.strong,{children:"re-reading more"}),"."]}),"\n",(0,o.jsx)(n,{type:"key",items:["The cost driver is re-reading, not thinking. Each loop step re-processes the full transcript, so a 20-step run pays for early context ~20 times over.","This is why 'just let the agent figure it out' is expensive: every extra step it takes multiplies against everything before it.","Output-heavy tasks (write me an essay) are cheap by comparison; input-heavy loops (explore this repo, then fix the bug) are where the money goes."]}),"\n",(0,o.jsx)(t.h2,{id:"the-numbers-that-surprise-people",children:"The numbers that surprise people"}),"\n",(0,o.jsx)(t.p,{children:"Three figures reset most people's intuition:"}),"\n",(0,o.jsxs)(t.ul,{children:["\n",(0,o.jsxs)(t.li,{children:[(0,o.jsx)(t.strong,{children:"~1000x."})," Agentic tasks can consume roughly a thousand times the tokens of an equivalent chat or code-completion, per the Stanford analysis \u2014 driven by the snowball above, not by a bigger model."]}),"\n",(0,o.jsxs)(t.li,{children:[(0,o.jsxs)(t.strong,{children:["Up to 30x variance on the ",(0,o.jsx)(t.em,{children:"same"})," task."]})," The same agent, run on the ",(0,o.jsx)(t.em,{children:"same"})," task, can cost up to ",(0,o.jsx)(t.strong,{children:"30x more one time than another"}),' \u2014 because the path it takes (how many tools it calls, how far it wanders) is non-deterministic. You genuinely cannot know the bill until it\'s done. This is why "result-based pricing" for agents is so hard: you only see the cost ',(0,o.jsx)(t.strong,{children:"after"})," everything runs."]}),"\n",(0,o.jsxs)(t.li,{children:[(0,o.jsx)(t.strong,{children:"More agents rarely pay for themselves."})," 2026 production benchmarks found that a multi-agent setup added only ",(0,o.jsx)(t.strong,{children:"~2.1% accuracy at 2x the cost"})," versus a well-configured single agent on 64% of tasks. A hierarchical-supervisor pattern pushed a document task from 85% \u2192 95% accuracy \u2014 but at roughly ",(0,o.jsx)(t.strong,{children:"$0.15/task vs $0.003"})," for the single agent (~50x). More agents buys a little accuracy for a lot of money."]}),"\n"]}),"\n",(0,o.jsx)(n,{type:"warning",items:["Because the same task varies up to 30x, an average-based budget WILL be blown by the tail. Cap the ceiling, don't budget the mean.","Adding agents to 'be safe' usually multiplies cost far faster than it adds accuracy. Reach for a second agent only when the task genuinely decomposes into parallel, independent subtasks."]}),"\n",(0,o.jsx)(t.h2,{id:"your-tool-surface-is-part-of-the-bill",children:"Your tool surface is part of the bill"}),"\n",(0,o.jsxs)(t.p,{children:["Before the loop even starts, ",(0,o.jsx)(t.strong,{children:"how the agent reaches its tools"})," sets a floor on cost. Connecting a set of MCP servers can inject tens of thousands of tokens of tool definitions into ",(0,o.jsx)(t.em,{children:"every"})," step of the snowball. A rough comparison many builders hit: a plain ",(0,o.jsx)(t.strong,{children:"CLI command averages ~200 tokens"}),", while the ",(0,o.jsx)(t.strong,{children:"equivalent MCP operation can cost 32k\u201382k tokens"})," once tool schemas and wrapping are counted. That gap rides along on every loop step."]}),"\n",(0,o.jsxs)(t.p,{children:["That doesn't make MCP wrong \u2014 it's the right choice for auth, multi-tenancy, and governed access. It means the tool surface is a ",(0,o.jsx)(t.strong,{children:"cost lever you chose at design time"}),". AILmanac has a dedicated deep-dive: ",(0,o.jsx)(t.a,{href:"/docs/claude-code/mcp-token-cost",children:"The MCP Token Tax"})," covers Tool Search, deferred loading, and code execution as the three fixes."]}),"\n",(0,o.jsx)(t.h2,{id:"the-four-levers-that-actually-cut-the-bill",children:"The four levers that actually cut the bill"}),"\n",(0,o.jsx)(t.p,{children:"Optimization advice is endless; only four levers move the number materially. In rough order of leverage:"}),"\n",(0,o.jsx)(c,{items:[{title:"Cap the budget \u2014 a hard ceiling, not a hope",body:"Set a per-run or per-user token/dollar cap that HARD-STOPS the agent. Because the same task can cost 30x more on a bad run, a ceiling is the only thing that bounds the tail. Most agent harnesses expose a max-tokens or max-steps limit \u2014 use it. This is the single most important control."},{title:"Cache the stable prefix",body:"The system prompt, tool definitions, and house rules are re-sent on every loop step (the snowball). Prompt caching charges those repeated tokens at a fraction of the input rate. On a long agentic run this is often the biggest single saving, because the cached part is exactly what gets re-read the most."},{title:"Route by model tier",body:"Don't run one frontier model for the whole loop. Use a cheap, fast model (Haiku-class, or a small open model) for the grunt work \u2014 reading files, formatting, routine tool calls \u2014 and reserve the expensive frontier model for the hard reasoning or the orchestrator role. Orchestrator-worker splits with cheaper workers cut cost 40\u201360% in production benchmarks at near-parity accuracy."},{title:"Prune the context aggressively",body:"The snowball is the problem, so shrink it. Compact old turns, drop tool outputs the agent no longer needs, summarize instead of carrying raw transcripts, and start fresh sub-tasks with a clean context instead of one ever-growing thread. Every token you remove is a token you stop paying for on EVERY remaining step."}]}),"\n",(0,o.jsx)(i,{title:"Audit a runaway agent (paste your run's token breakdown)",children:`You are a cost engineer. Here is a token-usage breakdown of one agentic run
(input vs output tokens per step, tool calls, model used).

Diagnose where the money went, in priority order:
1. Is input or output driving cost? (Agents are almost always input-heavy.)
2. Which repeated content should be prompt-CACHED (system prompt, tools, rules)?
3. Which steps could run on a CHEAPER model without losing correctness?
4. Where is context snowballing \u{2014} what can be pruned, compacted, or summarized?
5. What is a safe per-run token CAP that stops the worst tail without hurting the median run?

Give me the estimated % saving per fix and the ONE change to make first.`}),"\n",(0,o.jsx)(t.h2,{id:"when-an-agent-is-the-wrong-tool",children:"When an agent is the wrong tool"}),"\n",(0,o.jsxs)(t.p,{children:["The cheapest agentic run is the one you don't make. If a task is a ",(0,o.jsx)(t.strong,{children:"single, well-specified transformation"})," \u2014 summarize this, classify that, rewrite this \u2014 a plain chat/completion call does it at a fraction of the cost, with ",(0,o.jsx)(t.strong,{children:"no snowball at all"}),". Reach for an agent when the work genuinely requires ",(0,o.jsx)(t.em,{children:"reading, deciding, acting, and re-checking in a loop"})," against a changing environment (explore a repo, debug across files, drive a browser). If you can write the exact steps yourself, script them \u2014 don't pay a model to re-derive them every run."]}),"\n",(0,o.jsx)(s,{cards:[{front:"Context snowball",back:"The accumulated transcript an agent re-reads on every loop step. It grows each step, so total input cost scales ~quadratically with the number of steps."},{front:"Re-read tax",back:"The cost of re-processing the full prior context on each agent step. It's why agents are input-heavy and why cost is dominated by re-reading, not generating."},{front:"Model-tier routing",back:"Using a cheap/fast model for grunt work and reserving the frontier model for hard reasoning or the orchestrator. A top cost lever (40\u201360% savings in benchmarks)."},{front:"Orchestrator-worker",back:"One capable model plans and delegates subtasks to cheaper worker models that assemble results. Cuts cost when tasks decompose; wasteful when they don't."},{front:"Budget cap",back:"A hard token/dollar ceiling that stops an agent. The only reliable control for the tail, since the same task can cost up to 30x more on a bad run."}]}),"\n",(0,o.jsx)(l,{questions:[{q:"Why does an agentic run cost so much more than a single chat turn for the same question?",options:["Agents use a bigger, more expensive model by default","Each loop step re-reads the whole accumulated transcript, so input cost grows roughly quadratically with steps","Output tokens are priced far higher for agents","Agents disable prompt caching"],answer:1,explain:"The context snowball: every step re-processes the full prior context. Cost is driven by re-reading input, not by a bigger model or more output."},{q:"A teammate wants to add a second and third agent 'to be safe' on a task a single agent already handles at 85% accuracy. What do the 2026 benchmarks suggest?",options:["Always add agents \u2014 accuracy scales linearly with agent count","Extra agents typically buy a little accuracy for a lot of cost (e.g. +10 points but ~50x/task); add them only when the task truly decomposes","Multi-agent is always cheaper because each agent is smaller","It makes no difference to cost"],answer:1,explain:"Benchmarks showed ~2.1% accuracy at 2x cost on most tasks, and a hierarchical supervisor hitting ~50x per-task cost for ~10 points. More agents is a poor default."},{q:"Given that the SAME task can cost up to 30x more on one run than another, what's the right way to control spend?",options:["Budget for the average run cost","Set a hard per-run token/dollar cap that stops the agent, since the tail \u2014 not the mean \u2014 blows the budget","Turn off tool use","Only run agents overnight"],answer:1,explain:"Because cost is non-deterministic with a heavy tail, an average-based budget gets blown by bad runs. A hard ceiling bounds the worst case."}]}),"\n",(0,o.jsx)(t.h2,{id:"sources--further-reading",children:"Sources & further reading"}),"\n",(0,o.jsxs)(t.ul,{children:["\n",(0,o.jsxs)(t.li,{children:[(0,o.jsx)(t.a,{href:"https://digitaleconomy.stanford.edu/news/how-are-ai-agents-spending-your-tokens/",children:"How Are AI Agents Spending Your Tokens? \u2014 Stanford Digital Economy Lab"})," \u2014 the ~1000x figure, the re-read/snowball mechanism, and the up-to-30x same-task variance."]}),"\n",(0,o.jsxs)(t.li,{children:[(0,o.jsx)(t.a,{href:"https://arxiv.org/abs/2603.22651",children:"Benchmarking Multi-Agent LLM Architectures: Orchestration Patterns and Cost-Accuracy Tradeoffs (arXiv 2603.22651)"})," \u2014 single vs multi-agent accuracy-per-dollar, hierarchical supervisor cost figures."]}),"\n",(0,o.jsxs)(t.li,{children:[(0,o.jsx)(t.a,{href:"https://arxiv.org/html/2605.05007v1",children:"Uno-Orchestra: Parsimonious Agent Routing via Selective Delegation (arXiv 2605.05007)"})," \u2014 collapsing orchestration to a single cheap worker on simple queries."]}),"\n",(0,o.jsxs)(t.li,{children:[(0,o.jsx)(t.a,{href:"https://www.anthropic.com/engineering/advanced-tool-use",children:"Anthropic \u2014 Advanced tool use / MCP token cost"})," \u2014 tool-definition token overhead and the CLI-vs-MCP gap (see our ",(0,o.jsx)(t.a,{href:"/docs/claude-code/mcp-token-cost",children:"MCP Token Tax"}),")."]}),"\n",(0,o.jsxs)(t.li,{children:["AILmanac companions: ",(0,o.jsx)(t.a,{href:"/docs/models/what-ai-costs-across-providers",children:"What AI Actually Costs (Across Providers)"})," \xb7 ",(0,o.jsx)(t.a,{href:"/docs/power-user/token-economy",children:"The Token Economy"})," \xb7 ",(0,o.jsx)(t.a,{href:"/docs/tools/cost-calculator",children:"Cost Calculator"}),"."]}),"\n"]})]})}function d(e={}){let{wrapper:t}={...(0,a.R)(),...e.components};return t?(0,o.jsx)(t,{...e,children:(0,o.jsx)(h,{...e})}):h(e)}function u(e,t){throw Error("Expected "+(t?"component":"object")+" `"+e+"` to be defined: you likely forgot to import, pass, or provide it.")}},28453(e,t,n){n.d(t,{R:()=>r,x:()=>i});var s=n(96540);let o={},a=s.createContext(o);function r(e){let t=s.useContext(a);return s.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function i(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(o):e.components||o:r(e.components),s.createElement(a.Provider,{value:t},e.children)}}}]);